import{_ as e,a as t,b as i}from"./chunks/支持留言.NiGCLVdp.js";import{_ as s,o as l,c as o,a2 as p}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"المدونة","description":"","frontmatter":{},"headers":[],"relativePath":"ar-SA/Other/blog.md","filePath":"ar-SA/Other/blog.md","lastUpdated":1781962217000}'),n={name:"ar-SA/Other/blog.md"};function d(c,a,r,h,g,b){return l(),o("div",null,[...a[0]||(a[0]=[p('<h1 id="المدونة" tabindex="-1">المدونة <a class="header-anchor" href="#المدونة" aria-label="Permalink to &quot;المدونة&quot;">​</a></h1><p>تضيف ميزة المدونة صفحة Blog مستقلة إلى موقع ImgBed.</p><p>بعد تفعيلها يستطيع الزوار فتح:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/blog/</span></span></code></pre></div><p><img src="'+e+'" alt="الصفحة الرئيسية للمدونة" loading="lazy"></p><p>المدونة مبنية بتكييف من مشروع <a href="https://github.com/LyraVoid/Mizuki" target="_blank" rel="noreferrer">LyraVoid/Mizuki</a> المفتوح المصدر. يعيد ImgBed دمجها مع Vue لتعمل كجزء من موقع استضافة الصور.</p><h2 id="أين-تضبطها؟" tabindex="-1">أين تضبطها؟ <a class="header-anchor" href="#أين-تضبطها؟" aria-label="Permalink to &quot;أين تضبطها؟&quot;">​</a></h2><p>إعدادات المدونة موجودة ضمن:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Blog</span></span></code></pre></div><p><img src="'+t+'" alt="إعدادات المدونة" loading="lazy"></p><h2 id="الإعداد-لأول-مرة" tabindex="-1">الإعداد لأول مرة <a class="header-anchor" href="#الإعداد-لأول-مرة" aria-label="Permalink to &quot;الإعداد لأول مرة&quot;">​</a></h2><ol><li>فعّل <code>Enable</code>.</li><li>اختر حساب GitHub الذي سيحفظ إعدادات المدونة.</li><li>اضغط <code>Update Blog</code>.</li><li>انتظر رسالة النجاح.</li><li>افتح <code>https://your-domain.com/blog/</code> لمشاهدة المدونة.</li></ol><p>في أول استخدام، يجهز ImgBed مستودع GitHub خاصًا تحت الحساب المختار:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>يحفظ هذا المستودع إعدادات المدونة ومحتوى المقالات.</p><h2 id="كتابة-المقالات" tabindex="-1">كتابة المقالات <a class="header-anchor" href="#كتابة-المقالات" aria-label="Permalink to &quot;كتابة المقالات&quot;">​</a></h2><p>عدّل مقالات المدونة داخل مستودع GitHub الخاص:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>المسار المعتاد:</p><ol><li>افتح GitHub.</li><li>ادخل إلى مستودع <code>imgbed-blog-config</code> الخاص.</li><li>عدّل ملفات المقالات أو أضف ملفات جديدة.</li><li>اعمل commit للتغييرات.</li><li>ارجع إلى لوحة إدارة ImgBed واضغط <code>Update Blog</code>، أو اضغط شعار أعلى يسار صفحة المدونة الرئيسية ثلاث مرات لتشغيل تحديث المدونة.</li></ol><p><code>Update Blog</code> لا يكتب فوق المحتوى الذي كتبته. يهيئ المستودع عند الحاجة ويحدّث كاش المدونة.</p><h2 id="الميزات-المدعومة" tabindex="-1">الميزات المدعومة <a class="header-anchor" href="#الميزات-المدعومة" aria-label="Permalink to &quot;الميزات المدعومة&quot;">​</a></h2><p>تدعم المدونة ميزات مألوفة مثل قائمة المقالات، والتصنيفات، والوسوم، والأرشيف، والبحث، والوضع الداكن، وتغيير اللغة.</p><p>كما تدعم التعليقات وإحصاءات الزيارات.</p><p><img src="'+i+'" alt="تعليقات المدونة" loading="lazy"></p><p>تظهر التعليقات أسفل المقالات. يمكن للزوار إدخال avatar و nickname و email ومحتوى التعليق.</p><p>تعرض إحصاءات الزيارات مشاهدات المقالات وزيارات الموقع، ما يساعدك على فهم حركة المدونة.</p><h2 id="الرابط" tabindex="-1">الرابط <a class="header-anchor" href="#الرابط" aria-label="Permalink to &quot;الرابط&quot;">​</a></h2><p>تُقدّم المدونة دائمًا تحت <code>/blog/</code>.</p><p>إذا كان نطاق ImgBed هو:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com</span></span></code></pre></div><p>فسيكون رابط المدونة:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com/blog/</span></span></code></pre></div><p>بعد تعطيل المدونة لن يستطيع الزوار الوصول إلى صفحة المدونة.</p>',34)])])}const k=s(n,[["render",d]]);export{v as __pageData,k as default};
